SELECT COUNT(notification_id) AS total_unread_notifications
FROM user_notifications
WHERE is_read = 0;

SELECT AVG(session_count) AS average_sessions_per_user
FROM (
    SELECT user_id, COUNT(session_id) AS session_count
    FROM user_sessions
    GROUP BY user_id
) AS session_counts;

SELECT username, email
FROM users
ORDER BY last_login DESC;

SELECT notification_type, COUNT(*) AS total_notifications
FROM user_notifications
GROUP BY notification_type;

SELECT username
FROM users
WHERE last_login = (SELECT MIN(last_login) FROM users);

SELECT username
FROM users
WHERE last_login >= date('now', '-7 days');
